head.script:
/**
 * @component
 * @componentName udc_schInput
 * @pluginName 
 * @company
 * @developer
 * @category /cm/udc
 * @notSupportBrowser 
 * @version
 * @htmlRender
 * @icon
 * @disableIcon
 * @description
 * @width
 * @height 22px
 * @license
 * @imagePath
 * @homepage
 */

/**
 * @property
 * @name id
 * @category 01.Basic & ETC
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description desc
 */

/**
 * @property
 * @name class
 * @category 01.Basic & ETC
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description desc
 */

/**
 * @property
 * @name style
 * @category 01.Basic & ETC
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description desc
 */

/**
 * @property
 * @name refDataMap
 * @category 01.Basic & ETC
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 데이터맵 아이디
 */

/**
 * @property
 * @name iptNm
 * @category 01.Basic & ETC
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description 바인딩 input 명
 */

/**
 * @property
 * @name iptMandatory
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description input 필수값 여부
 */

/**
 * @property
 * @name iptObjType
 * @category 03.Data
 * @type string
 * @option
 * @default
 * @necessary N
 * @bindparent
 * @description input objType 속성
 */

scwin.onpageload = function() {
	var opts = $p.getOptions();
	var refDataMap = opts.refDataMap;

    if(opts.iptMandatory) {
        ed_schInp.setMandatory(opts.iptMandatory);
    }
    if(opts.iptObjType) {
        ed_schInp.options.objType = opts.iptObjType;
    }

    if ( !refDataMap ) return;
    aliasDataMap.setScope("../"+refDataMap);
    ed_schInp.setRef("data:aliasDataMap."+opts.iptNm);
};

scwin.ed_schInp_ondblclick = function (e) {
    let schData = this.getValue().replace(/,/g, "\n");
    txt_schArea.setValue(schData);

    txt_schArea.show("");    
    setTimeout(function() {
        txt_schArea.focus();
    }, 100);

};

scwin.txt_schArea_onblur = function (e) {
    let schData = this.getValue().replace(/\n/g, ",");
    ed_schInp.setValue(schData);
    txt_schArea.hide();  
};

/**
 * @method
 * @name setData
 * @description 데이터 셋팅
 * @param {string} param1 desc
 * @returns
 * @hidden N
 * @exception
 * @example
 */
scwin.setData = function (param1) {
    ed_schInp.setValue(param1);
};
